import subprocess,base64,datetime,time,json,os
P1='192.168.10.19'
WEB='/var/www/html'
MP='/mnt/vnt-data/FileServer/VNT_World_AI_Division/MemPalace.md'
TSF=datetime.datetime.now().strftime('%Y%m%d_%H%M')

# HTML embedded as base64 chunks - no config dependency
PARTS=[
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
]
HTML=base64.b64decode(b''.join(PARTS))
print(f'HTML ready: {len(HTML)} bytes')

def rx(h,c,t=30):
    r=subprocess.run(['ssh','-o','StrictHostKeyChecking=no','-o','ConnectTimeout=8','root@'+h,c],capture_output=True,text=True,timeout=t)
    return (r.stdout+r.stderr).strip()

def pct_e(id,c,t=60):
    r=subprocess.run(['ssh','-o','StrictHostKeyChecking=no','-o','ConnectTimeout=8','root@'+P1,'pct exec '+str(id)+' -- bash -c '+json.dumps(c)],capture_output=True,text=True,timeout=t)
    return (r.stdout+r.stderr).strip()

def save(e):
    try: open(MP,'a').write('\n### CT108 ['+TSF+']\n'+e+'\n')
    except: pass

print('='*55)
print('DEPLOY CT108 DASHBOARD v2')
print(TSF)
print('='*55)

# Verify CT108 running
st=rx(P1,'pct status 108')
print('[1] CT108:',st)
if 'stopped' in st.lower():
    rx(P1,'pct start 108',t=20); time.sleep(8)

# BACKUP - non-negotiable
print('[2] Backup...')
bk=pct_e(108,f'cp {WEB}/dashboard.html {WEB}/dashboard.html.bak_{TSF} && echo OK')
print(' ',bk)
os.makedirs('/root/ct108_backups',exist_ok=True)
rx(P1,f'pct pull 108 {WEB}/dashboard.html /root/ct108_backups/dash_{TSF}.html',t=20)
print(' Prox1 backup: /root/ct108_backups/dash_'+TSF+'.html')

# Write HTML to MSI temp then push to CT108
print('[3] Writing to CT108...')
open('/tmp/new_dash.html','wb').write(HTML)
push_r=rx(P1,'pct push 108 /tmp/new_dash.html '+WEB+'/dashboard.html',t=30)
print(' pct push:',push_r or 'OK')

# Verify
v=pct_e(108,f'wc -c {WEB}/dashboard.html')
g=pct_e(108,f'grep -c GAMES {WEB}/dashboard.html 2>/dev/null || echo 0')
print('[4] Size:',v,'| GAMES count:',g)

# Reload nginx
nr=pct_e(108,'nginx -s reload 2>/dev/null || service nginx reload 2>/dev/null || echo reloaded')
print('[5] Nginx:',nr[:60])

# Update vnt_config
CFG='/mnt/vnt-data/FileServer/VNT_World_AI_Division/vnt_config.json'
try:
    cfg=json.load(open(CFG))
except: cfg={}
cfg.update({'production_web_ct':'108','production_web_root':WEB,'production_domain':'vntworld.com','never_write_to':'/home/k/vnt-web','ct108_last_deploy':TSF})
json.dump(cfg,open(CFG,'w'),indent=2)

save('CT108 v2 deployed '+TSF+'\nBackup: '+WEB+'/dashboard.html.bak_'+TSF+'\nROLLBACK: pct exec 108 -- bash -c cp '+WEB+'/dashboard.html.bak_'+TSF+' '+WEB+'/dashboard.html')
print('='*55)
print('DONE: vntworld.com/dashboard.html updated')
print('Rollback: pct exec 108 -- bash -c "cp '+WEB+'/dashboard.html.bak_'+TSF+' '+WEB+'/dashboard.html"')
print('='*55)